from sklearn.model_selection import train_test_split

# First split: Train vs Temp
train_df, temp_df = train_test_split(
    df,
    test_size=0.30,
    stratify=df[LABEL_COLUMN],
    random_state=42
)

# Second split: Validation vs Test
