from tensorflow.keras.preprocessing.image import ImageDataGenerator

train_datagen = ImageDataGenerator(
    rescale=1./255,
    rotation_range=20,
    width_shift_range=0.1,
    height_shift_range=0.1,
    zoom_range=0.1,
    horizontal_flip=True
)

val_test_datagen = ImageDataGenerator(
    rescale=1./255
)

BATCH_SIZE = 32
IMAGE_SIZE = (224, 224)

train_generator = train_datagen.flow_from_dataframe(
    dataframe=train_df,
    directory=actual_image_dir,
    x_col=FILENAME_COLUMN,
    y_col=LABEL_COLUMN,
    target_size=IMAGE_SIZE,
    batch_size=BATCH_SIZE,
    class_mode='binary'
)

val_generator = val_test_datagen.flow_from_dataframe(
    dataframe=val_df,
    directory=actual_image_dir,
    x_col=FILENAME_COLUMN,
    y_col=LABEL_COLUMN,
    target_size=IMAGE_SIZE,
    batch_size=BATCH_SIZE,
    class_mode='binary'
)

test_generator = val_test_datagen.flow_from_dataframe(
    dataframe=test_df,
    directory=actual_image_dir,
    x_col=FILENAME_COLUMN,
    y_col=LABEL_COLUMN,
    target_size=IMAGE_SIZE,
    batch_size=BATCH_SIZE,
    class_mode='binary',
    shuffle=False
)

print("\nGenerator Summary")

print("Training batches:", train_generator.samples)
print("Validation batches:", val_generator.samples)
print("Test batches:", test_generator.samples)

from tensorflow.keras.callbacks import EarlyStopping, ReduceLROnPlateau, ModelCheckpoint
import matplotlib.pyplot as plt

#Training  callback
early_stop = EarlyStopping(
    monitor='val_loss',
    patience=5,
    restore_best_weights=True
)

reduce_lr = ReduceLROnPlateau(
    monitor='val_loss',
    factor=0.3,
    patience=3,
    min_lr=1e-6
)

checkpoint_custom = ModelCheckpoint(
    "best_custom_model.h5",
    monitor="val_loss",
    save_best_only=True
)

checkpoint_pretrained = ModelCheckpoint(
    "best_pretrained_model.h5",
    monitor="val_loss",
    save_best_only=True
)

"""===========================================================================================
CUSTOM MODEL

===========================================================================================

Let's visualize how our custom model will looks like and how the mathematical operation will be peformed

![Screenshot 2026-03-24 194514.png](data:image/png;base64,)

![Screenshot 2026-03-24 194304.png](data:image/png;base64,)

![Screenshot 2026-03-24 194717.png](data:image/png;base64,)
"""

from tensorflow.keras import layers, models

custom_model = models.Sequential([
    layers.Conv2D(32, (3, 3), activation='relu', input_shape=(224, 224, 3)),
    layers.MaxPooling2D((2, 2)),

    layers.Conv2D(64, (3, 3), activation='relu'),
    layers.MaxPooling2D((2, 2)),

    layers.Conv2D(128, (3, 3), activation='relu'),
    layers.MaxPooling2D((2, 2)),

    layers.Flatten(),
    layers.Dense(128, activation='relu'),
    layers.Dropout(0.5),
    layers.Dense(1, activation='sigmoid')
])

custom_model.compile(
    optimizer='adam',
    loss='binary_crossentropy',
    metrics=['accuracy']
)

custom_model.summary()

print("Training Custom Model...")

history_custom = custom_model.fit(
    train_generator,
    epochs=15,
    validation_data=val_generator,
    callbacks=[early_stop, reduce_lr, checkpoint_custom]
)

print("Evaluating Custom Model on Test Data")

test_loss_custom, test_acc_custom = custom_model.evaluate(test_generator)

print("Custom Model Test Accuracy:", test_acc_custom)

"""===========================================================================================
PRETAINED MODEL
===========================================================================================

Let's visualize how our pretrained model works. mathematical operation in MobilNetV2 architecture are almost similar to custom CNN. The differences are new blocks are introduced such as Residual which helps to reduce computational cost and reduce long-term dependencies

![Screenshot 2026-03-24 195126.png](data:image/png;base64,)
"""

from tensorflow.keras.applications import MobileNetV2

base_model = MobileNetV2(
    input_shape=(224, 224, 3),
    include_top=False,
    weights='imagenet'
)

base_model.trainable = False

pretrained_model = models.Sequential([
    base_model,
    layers.GlobalAveragePooling2D(),
    layers.Dense(128, activation='relu'),
    layers.Dropout(0.5),
    layers.Dense(1, activation='sigmoid')
])

pretrained_model.compile(
    optimizer='adam',
    loss='binary_crossentropy',
    metrics=['accuracy']
)

pretrained_model.summary()

print("Training Pre-trained Model...")

history_pretrained = pretrained_model.fit(
    train_generator,
    epochs=15,
    validation_data=val_generator,
    callbacks=[reduce_lr, checkpoint_pretrained] # Removed early_stop to ensure all epochs run
)

print("Evaluating Pretrained Model on Test Data")

test_loss_pre, test_acc_pre = pretrained_model.evaluate(test_generator)

print("Pretrained Model Test Accuracy:", test_acc_pre)

